INSERT INTO hr."SafetyCommitteeMeeting" OVERRIDING SYSTEM VALUE VALUES (1, 1, '2025-09-10 09:00:00', NULL, 'Revision de indices de accidentalidad Q3 2025. Plan de accion para EPP. Actualizacion mapa de riesgos.', '1. Adquirir 50 pares de guantes de seguridad. 2. Actualizar mapa de riesgos antes del 30/09. 3. Programar charla EPP para operaciones.', '2026-03-30 15:40:54.730728');
INSERT INTO hr."SafetyCommitteeMeeting" OVERRIDING SYSTEM VALUE VALUES (2, 1, '2025-10-15 09:00:00', NULL, 'Seguimiento accidente V-25678901. Revision dotacion EPP. Evaluacion programa pausas activas.', '1. Verificar dotacion EPP completada. 2. Implementar programa pausas activas. 3. Notificar INPSASEL cierre investigacion.', '2026-03-30 15:40:54.730728');
INSERT INTO hr."SafetyCommitteeMeeting" OVERRIDING SYSTEM VALUE VALUES (3, 1, '2025-12-10 09:00:00', NULL, 'Balance anual SST 2025. Planificacion plan SST 2026. Renovacion certificaciones brigadas.', '1. Preparar informe anual INPSASEL. 2. Elaborar plan SST 2026 para enero. 3. Renovar certificaciones brigadas Q1 2026.', '2026-03-30 15:40:54.730728');
INSERT INTO hr."SafetyCommitteeMeeting" OVERRIDING SYSTEM VALUE VALUES (4, 2, '2025-12-08 10:00:00', NULL, 'Revision accidente grave V-22678901. Analisis causalidad. Plan correctivo deposito.', '1. Implementar sistema anti-caida pallets. 2. Verificar calzado seguridad 100% operaciones. 3. Simulacro evacuacion Q1 2026.', '2026-03-30 15:40:54.730728');
INSERT INTO hr."SafetyCommitteeMeeting" OVERRIDING SYSTEM VALUE VALUES (5, 2, '2026-01-12 10:00:00', NULL, 'Seguimiento plan correctivo deposito. Estado de reposo V-22678901. Preparacion informe INPSASEL.', '1. Documentar implementacion mejoras. 2. Informe INPSASEL antes del 15/02. 3. Planificar induccion nuevos operadores.', '2026-03-30 15:40:54.730728');
INSERT INTO hr."SafetyCommitteeMeeting" OVERRIDING SYSTEM VALUE VALUES (100, 100, '2026-01-20 00:00:00', NULL, '1. Revision accidentes Q4 2025. 2. Plan de capacitacion SST 2026. 3. Auditoria de extintores y senalizacion.', '- Programar inspeccion de extintores antes del 31/01. - Actualizar mapa de riesgos del almacen. - Coordinar charla de primeros auxilios con Cruz Roja.', '2026-03-30 15:40:54.99379');
INSERT INTO hr."SafetyCommitteeMeeting" OVERRIDING SYSTEM VALUE VALUES (101, 100, '2026-02-17 00:00:00', NULL, '1. Resultado inspeccion extintores. 2. Estadisticas accidentalidad enero. 3. Dotacion EPP primer trimestre.', '- Reemplazar 3 extintores vencidos en planta baja. - Solicitar cotizacion EPP nuevos ingresos. - Fijar fecha simulacro evacuacion marzo.', '2026-03-30 15:40:54.99379');
INSERT INTO hr."SafetyCommitteeMeeting" OVERRIDING SYSTEM VALUE VALUES (102, 100, '2026-03-16 00:00:00', NULL, '1. Simulacro de evacuacion realizado (3 min 20 seg). 2. Revision plan de emergencia. 3. Informe trimestral INPSASEL.', '- Documentar resultados simulacro para informe INPSASEL. - Corregir ruta evacuacion piso 2. - Entregar informe trimestral antes del 10/04.', '2026-03-30 15:40:54.99379');
INSERT INTO hr."SafetyCommitteeMeeting" OVERRIDING SYSTEM VALUE VALUES (103, 101, '2026-01-28 00:00:00', NULL, '1. Planificacion actividades recreativas Q1 2026. 2. Fondo de ayuda social: balance y solicitudes pendientes. 3. Convenio farmacia.', '- Organizar jornada deportiva para febrero. - Evaluar 2 solicitudes de ayuda economica. - Renovar convenio farmacia antes del 15/02.', '2026-03-30 15:40:54.99379');
