INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (395, 1, 'TEC-MOUSE-01', 5, 'Adios dolor de muneca', 'Desde que uso este mouse ergonomico se me quito el dolor de muneca.', 'Andrea G.', 'andrea@test.com', true, true, false, '2026-03-01 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (396, 1, 'TEC-MOUSE-01', 4, 'Muy comodo', 'El diseno ergonomico es excelente. La bateria dura semanas.', 'Cristian B.', 'cristian@test.com', true, true, false, '2026-03-09 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (397, 1, 'HOG-LIC-01', 5, 'Potente', 'Licua hasta hielo sin problemas. 700W de potencia real.', 'Rosa P.', 'rosa@test.com', true, true, false, '2026-03-04 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (398, 1, 'HOG-LIC-01', 4, 'Muy buena', 'Hago smoothies todos los dias. Facil de lavar y usar.', 'Manuel T.', 'manuel@test.com', false, true, false, '2026-03-12 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (399, 1, 'DEP-BAND-01', 5, 'Excelente set', '5 niveles de resistencia. Perfectas para entrenar en casa.', 'Valeria M.', 'valeria@test.com', true, true, false, '2026-03-05 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (400, 1, 'DEP-BAND-01', 5, 'Las uso todos los dias', 'Muy resistentes y no se deforman. Vienen con bolsa de transporte.', 'Esteban R.', 'esteban@test.com', false, true, false, '2026-03-13 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (401, 1, 'TEC-HUB-01', 5, 'Indispensable', '7 puertos en uno. HDMI funciona perfecto a 4K. Lo uso con mi MacBook.', 'Joaquin L.', 'joaquin@test.com', true, true, false, '2026-03-06 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (402, 1, 'TEC-HUB-01', 4, 'Muy practico', 'Todos los puertos funcionan bien. El cable es un poco corto.', 'Mariana F.', 'mariana@test.com', true, true, false, '2026-03-14 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (403, 1, 'ELEC-CHRG-01', 5, 'Carga rapida real', '15W de carga reales. Mi telefono se carga en 2 horas.', 'Daniela M.', 'daniela.m@test.com', true, true, false, '2026-03-07 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (404, 1, 'ELEC-CHRG-01', 4, 'Bueno y bonito', 'Diseno elegante y funcional. Compatible con todos mis dispositivos.', 'Martin R.', 'martin@test.com', false, true, false, '2026-03-15 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (405, 1, 'HOG-SART-01', 5, 'Excelentes sartenes', 'Nada se pega. Muy faciles de limpiar y el mango no se calienta.', 'Gloria T.', 'gloria@test.com', true, true, false, '2026-02-27 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (406, 1, 'HOG-SART-01', 4, 'Buena calidad', 'El set de 3 tamanos es perfecto. El antiadherente funciona bien.', 'Ramon L.', 'ramon@test.com', true, true, false, '2026-03-08 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (407, 1, 'DEP-BOT-01', 5, 'Mantiene la temperatura', 'Agua fria por 24 horas. Excelente calidad del acero.', 'Camilo V.', 'camilo@test.com', true, true, false, '2026-03-10 19:07:56.051039');
INSERT INTO store."ProductReview" OVERRIDING SYSTEM VALUE VALUES (408, 1, 'DEP-BOT-01', 4, 'Perfecta para el gym', '1 litro es suficiente. No gotea y el diseno es muy bonito.', 'Silvia G.', 'silvia@test.com', false, true, false, '2026-03-18 19:07:56.051039');
